mapper.select:
SELECT round_id, round_number, start_time, end_time, status, remark, created_at, updated_at
FROM supplement_round
WHERE round_id = #{roundId, typeHandler=com.campus.platform.handler.UUIDJdbcTypeHandler}

SELECT round_id, round_number, start_time, end_time, status, remark, created_at, updated_at
FROM supplement_round
WHERE status = 'ACTIVE'
  AND start_time <= #{now}
  AND end_time >= #{now}
LIMIT 1
